import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.CuEaBji2.js";const b=JSON.parse('{"title":"流量统计原理","description":"","frontmatter":{},"headers":[],"relativePath":"reference/traffic-accounting.md","filePath":"reference/traffic-accounting.md","lastUpdated":1782021666000}'),i={name:"reference/traffic-accounting.md"};function n(o,t,l,s,c,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="流量统计原理" tabindex="-1">流量统计原理 <a class="header-anchor" href="#流量统计原理" aria-label="Permalink to &quot;流量统计原理&quot;">​</a></h1><p>控制面通过读取 Agent 节点的网络接口计数器来统计流量，按月度执行配额管理。</p><h2 id="采集流程" tabindex="-1">采集流程 <a class="header-anchor" href="#采集流程" aria-label="Permalink to &quot;采集流程&quot;">​</a></h2><ol><li>Agent 通过 netlink 读取内核网络接口计数器。netlink 失败则回退到 <code>/proc/net/dev</code></li><li>Agent 读取 <code>/proc/sys/kernel/random/boot_id</code> 检测系统重启</li><li>接口被重建或计数器回滚时，Agent 记录一次重置并使用当前值作为新基准，防止负数或不正确扣除</li><li>控制面存储原始游标值、每小时桶、每日汇总、每月汇总、节点策略、校准基准和事件</li></ol><h2 id="接口筛选" tabindex="-1">接口筛选 <a class="header-anchor" href="#接口筛选" aria-label="Permalink to &quot;接口筛选&quot;">​</a></h2><p>默认采集所有接口。限制到特定接口：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_TRAFFIC_INTERFACES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=eth0,eth1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Agent 在 Docker bridge 网络中只能看到容器内部流量。要采集宿主机总流量，用 host 网络模式或直接在宿主机部署 Agent。</p><h2 id="计费周期" tabindex="-1">计费周期 <a class="header-anchor" href="#计费周期" aria-label="Permalink to &quot;计费周期&quot;">​</a></h2><p>每个 Agent 有一个流量策略，控制统计和阻断行为：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>计数方向</td><td>入站（rx）、出站（tx）、双向、取大值、混合公式</td></tr><tr><td>计费起始日</td><td>月度重置日（1–31），默认 1 号</td></tr><tr><td>月度额度</td><td>每月最大流量。留空 = 不限</td></tr><tr><td>超额阻断</td><td>开启后达到额度阻止该节点</td></tr></tbody></table><p>被阻断的节点在面板显示 <code>traffic_blocked</code>。下个计费周期自动恢复。</p><h2 id="数据保留" tabindex="-1">数据保留 <a class="header-anchor" href="#数据保留" aria-label="Permalink to &quot;数据保留&quot;">​</a></h2><table tabindex="0"><thead><tr><th>粒度</th><th>默认保留</th><th>存储内容</th></tr></thead><tbody><tr><td>每小时桶</td><td>30 天</td><td>详细每小时数据</td></tr><tr><td>每日汇总</td><td>3 个月</td><td>聚合每日总量</td></tr><tr><td>每月汇总</td><td>24 个月</td><td>聚合每月总量</td></tr></tbody></table><p>控制面按 <code>NRE_TRAFFIC_CLEANUP_INTERVAL</code>（默认 24h）自动清理过期数据。</p><h2 id="手动校准" tabindex="-1">手动校准 <a class="header-anchor" href="#手动校准" aria-label="Permalink to &quot;手动校准&quot;">​</a></h2><p>更换网卡、重装系统或迁移数据后，物理计数器可能与实际使用量不匹配。在节点详情页操作：</p><ul><li><strong>设置基准偏移</strong>：从当前计数器增减固定量</li><li><strong>清除当前周期</strong>：当前计费周期归零</li></ul><p>校准基准保存在 <code>traffic_baselines</code> 中，后续统计使用校准值。</p><h2 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h2><p>操作指南见 <a href="./../guides/traffic-quota">流量额度</a>。</p>',21)])])}const u=e(i,[["render",n]]);export{b as __pageData,u as default};
